  'MAHARASHTRA': 'MAHARASHTRA',
  'NORTH EAST': 'NORTH EAST', 'NORTHEAST': 'NORTH EAST',
  'ARUNACHAL PRADESH': 'NORTH EAST', 'MANIPUR': 'NORTH EAST', 'MEGHALAYA': 'NORTH EAST',
  'MIZORAM': 'NORTH EAST', 'NAGALAND': 'NORTH EAST', 'TRIPURA': 'NORTH EAST',
  'ODISHA': 'ODISHA', 'ORISSA': 'ODISHA',
